package common

import (
	"encoding/base64"
	"fmt"
	"path/filepath"
	"strings"
)

var (
	Description = "Client used to connect and manage the server ahd the connection to the agent." +
		"\nThe client will try to load configuration from " + filepath.Join("$HOME", ".config", fmt.Sprintf("%s.yaml", strings.ToLower(APP_NAME))) +
		"\nAs well as " + fmt.Sprintf("%s.yaml", strings.ToLower(APP_NAME)) + " on the current directory."
	b64banner = ``
)

const APP_NAME = "tealc"

func GetBanner() string {
	res, err := base64.StdEncoding.DecodeString(b64banner)
	if err != nil {
		return ""
	}
	return string(res)
}
